async function loadUser(phone) {
  try {
    const raw = localStorage.getItem(`user:${phone}`);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}
async function saveUser(phone, data) {
  try {
    localStorage.setItem(`user:${phone}`, JSON.stringify(data));
  } catch (e) {
    console.error("save failed", e);
  }
}

