function Button({ children, onClick, variant = "primary", style, type = "button", disabled }) {
  const base = {
    border: "none",
    borderRadius: 12,
    padding: "14px 20px",
    fontSize: 15,
    fontWeight: 700,
    cursor: disabled ? "not-allowed" : "pointer",
    width: "100%",
    fontFamily: "inherit",
    transition: "transform 0.08s ease, opacity 0.2s",
    opacity: disabled ? 0.5 : 1,
  };
  const variants = {
    primary: { background: ACCENT, color: BG },
    secondary: { background: "transparent", color: ACCENT, border: `1.5px solid ${ACCENT}` },
    ghost: { background: CARD, color: "#fff", border: `1px solid ${LINE}` },
  };
  return (
    <button
      type={type}
      disabled={disabled}
      onClick={onClick}
      onMouseDown={(e) => (e.currentTarget.style.transform = "scale(0.98)")}
      onMouseUp={(e) => (e.currentTarget.style.transform = "scale(1)")}
      style={{ ...base, ...variants[variant], ...style }}
    >
      {children}
    </button>
  );
}

function Input({ label, ...props }) {
  return (
    <label style={{ display: "block", marginBottom: 14 }}>
      <div style={{ fontSize: 13, color: "#9a9a9d", marginBottom: 6, fontWeight: 600 }}>{label}</div>
      <input
        {...props}
        style={{
          width: "100%",
          background: "#0F0F10",
          border: `1.5px solid ${LINE}`,
          borderRadius: 10,
          padding: "12px 14px",
          color: "#fff",
          fontSize: 15,
          fontFamily: "inherit",
          outline: "none",
          boxSizing: "border-box",
        }}
        onFocus={(e) => (e.target.style.borderColor = ACCENT)}
        onBlur={(e) => (e.target.style.borderColor = LINE)}
      />
    </label>
  );
}

function Select({ label, options, value, onChange }) {
  return (
    <label style={{ display: "block", marginBottom: 14 }}>
      <div style={{ fontSize: 13, color: "#9a9a9d", marginBottom: 6, fontWeight: 600 }}>{label}</div>
      <select
        value={value}
        onChange={onChange}
        style={{
          width: "100%",
          background: "#0F0F10",
          border: `1.5px solid ${LINE}`,
          borderRadius: 10,
          padding: "12px 14px",
          color: "#fff",
          fontSize: 15,
          fontFamily: "inherit",
          outline: "none",
          boxSizing: "border-box",
        }}
      >
        {options.map((o) => (
          <option key={o} value={o}>{o}</option>
        ))}
      </select>
    </label>
  );
}

function AuthScreen({ onLogin }) {
  const [mode, setMode] = useState("login");
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [code, setCode] = useState("");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);

  const submit = async () => {
    setErr("");
    if (!phone.trim()) { setErr("اكتب رقم الموبايل"); return; }
    setLoading(true);
    const existing = await loadUser(phone.trim());
    if (mode === "signup") {
      if (existing) { setErr("الرقم ده مسجل قبل كده، سجل دخول"); setLoading(false); return; }
      if (!name.trim()) { setErr("اكتب اسمك"); setLoading(false); return; }
      if (!ACCESS_CODES.includes(code.trim().toUpperCase())) {
        setErr("كود الاشتراك غير صحيح، تأكد منه مع المدرب");
        setLoading(false);
        return;
      }
      const newUser = {
        phone: phone.trim(),
        name: name.trim(),
        onboarded: false,
        profile: {},
        progress: [],
        checkedDays: {},
      };
      await saveUser(phone.trim(), newUser);
      onLogin(newUser);
    } else {
      if (!existing) { setErr("الرقم غير مسجل، اعمل حساب جديد"); setLoading(false); return; }
      onLogin(existing);
    }
    setLoading(false);
  };

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "center", padding: 24 }}>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginBottom: 36 }}>
        <Logo size={40} showCoach />
      </div>
      <div style={{ background: CARD, borderRadius: 18, padding: 24, border: `1px solid ${LINE}` }}>
        <h2 style={{ margin: "0 0 4px", fontSize: 22, fontWeight: 800 }}>
          {mode === "login" ? "تسجيل الدخول" : "حساب جديد"}
        </h2>
        <p style={{ margin: "0 0 20px", color: "#9a9a9d", fontSize: 14 }}>
          {mode === "login" ? "اكتب رقم موبايلك للمتابعة" : "خلينا نبدأ رحلتك الرياضية"}
        </p>
        {mode === "signup" && <Input label="الاسم" placeholder="اسمك" value={name} onChange={(e) => setName(e.target.value)} />}
        <Input label="رقم الموبايل" placeholder="01xxxxxxxxx" value={phone} onChange={(e) => setPhone(e.target.value)} type="tel" />
        {mode === "signup" && <Input label="كود الاشتراك" placeholder="هتاخده من المدرب" value={code} onChange={(e) => setCode(e.target.value)} />}
        {err && <div style={{ color: "#ff5c5c", fontSize: 13, marginBottom: 12, fontWeight: 600 }}>{err}</div>}
        <Button onClick={submit} disabled={loading} style={{ marginTop: 6 }}>
          {loading ? "..." : mode === "login" ? (<span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}><LogIn size={18}/> دخول</span>) : (<span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}><UserPlus size={18}/> إنشاء حساب</span>)}
        </Button>
        <div style={{ textAlign: "center", marginTop: 16, fontSize: 14, color: "#9a9a9d" }}>
          {mode === "login" ? "مفيش حساب لسه؟" : "عندك حساب؟"}{" "}
          <span
            style={{ color: ACCENT, fontWeight: 700, cursor: "pointer" }}
            onClick={() => { setMode(mode === "login" ? "signup" : "login"); setErr(""); }}
          >
            {mode === "login" ? "اعمل حساب" : "سجل دخول"}
          </span>
        </div>
      </div>
      <WhatsAppContact />
    </div>
  );
}

function Onboarding({ user, onDone }) {
  const [age, setAge] = useState("");
  const [weight, setWeight] = useState("");
  const [height, setHeight] = useState("");
  const [target, setTarget] = useState("");
  const [goal, setGoal] = useState(GOALS[0]);
  const [level, setLevel] = useState(LEVELS[1]);
  const [err, setErr] = useState("");

  const submit = async () => {
    if (!age || !weight || !height || !target) { setErr("من فضلك كمل كل البيانات"); return; }
    const updated = {
      ...user,
      onboarded: true,
      profile: { age, weight, height, target, goal, level },
      progress: [{ date: new Date().toISOString().slice(0, 10), weight: Number(weight) }],
    };
    await saveUser(user.phone, updated);
    onDone(updated);
  };

  return (
    <div style={{ minHeight: "100vh", padding: "24px 20px 40px" }}>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginBottom: 28 }}>
        <Logo size={36} showCoach />
      </div>
      <h2 style={{ fontSize: 20, fontWeight: 800, marginBottom: 4 }}>أهلاً {user.name} 👋</h2>
      <p style={{ color: "#9a9a9d", fontSize: 14, marginBottom: 22 }}>
        كمّل بياناتك عشان نجهز ليك خطة التمارين والنظام الغذائي المناسب
      </p>
      <div style={{ background: CARD, borderRadius: 18, padding: 20, border: `1px solid ${LINE}` }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
          <Input label="السن" type="number" value={age} onChange={(e) => setAge(e.target.value)} placeholder="مثال: 25" />
          <Input label="الوزن الحالي (كجم)" type="number" value={weight} onChange={(e) => setWeight(e.target.value)} placeholder="مثال: 80" />
          <Input label="الطول (سم)" type="number" value={height} onChange={(e) => setHeight(e.target.value)} placeholder="مثال: 175" />
          <Input label="الوزن المستهدف (كجم)" type="number" value={target} onChange={(e) => setTarget(e.target.value)} placeholder="مثال: 75" />
        </div>
        <Select label="هدفك الأساسي" options={GOALS} value={goal} onChange={(e) => setGoal(e.target.value)} />
        <Select label="مستواك الحالي" options={LEVELS} value={level} onChange={(e) => setLevel(e.target.value)} />
        {err && <div style={{ color: "#ff5c5c", fontSize: 13, marginBottom: 12, fontWeight: 600 }}>{err}</div>}
        <Button onClick={submit} style={{ marginTop: 4 }}>
          <span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>تجهيز خطتي <ChevronLeft size={18}/></span>
        </Button>
      </div>
      <WhatsAppContact />
    </div>
  );
}

function Header({ title, subtitle }) {
  return (
    <div style={{ marginBottom: 18 }}>
      <h1 style={{ fontSize: 24, fontWeight: 800, margin: 0 }}>{title}</h1>
      {subtitle && <p style={{ color: "#9a9a9d", fontSize: 14, margin: "4px 0 0" }}>{subtitle}</p>}
    </div>
  );
}

function StatCard({ icon, label, value, unit }) {
  return (
    <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 14, padding: 14, flex: 1 }}>
      <div style={{ color: ACCENT, marginBottom: 8 }}>{icon}</div>
      <div style={{ fontSize: 20, fontWeight: 800 }}>{value}<span style={{ fontSize: 12, color: "#9a9a9d", fontWeight: 600 }}> {unit}</span></div>
      <div style={{ fontSize: 12, color: "#9a9a9d", marginTop: 2 }}>{label}</div>
    </div>
  );
}

function HomeTab({ user }) {
  const { profile, progress } = user;
  const currentWeight = progress[progress.length - 1]?.weight ?? profile.weight;
  const diff = (currentWeight - profile.target).toFixed(1);
  const today = DAYS[new Date().getDay() === 6 ? 0 : new Date().getDay() + 1];
  const todayWorkout = WORKOUT_TEMPLATES[profile.goal]?.[profile.level]?.[today] || [];

  return (
    <div>
      <Header title={`أهلاً، ${user.name} 💪`} subtitle={`هدفك: ${profile.goal} - مستوى ${profile.level}`} />
      <div style={{ display: "flex", gap: 10, marginBottom: 18 }}>
        <StatCard icon={<TrendingUp size={20} />} label="الوزن الحالي" value={currentWeight} unit="كجم" />
        <StatCard icon={<Target size={20} />} label="المستهدف" value={profile.target} unit="كجم" />
        <StatCard icon={<Flame size={20} />} label="متبقي" value={Math.abs(diff)} unit="كجم" />
      </div>

      <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 16, padding: 18, marginBottom: 14 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
          <Calendar size={18} color={ACCENT} />
          <span style={{ fontWeight: 800, fontSize: 15 }}>تمرين النهاردة - {today}</span>
        </div>
        {todayWorkout.length === 0 || todayWorkout[0] === "راحة" ? (
          <div style={{ color: "#9a9a9d", fontSize: 14 }}>يوم راحة 🛌 خد بالك من نفسك وارتاح كويس</div>
        ) : (
          <ul style={{ margin: 0, padding: 0, listStyle: "none", display: "flex", flexDirection: "column", gap: 8 }}>
            {todayWorkout.map((ex, i) => (
              <li key={i} style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 14, color: "#d8d8da" }}>
                <CheckCircle2 size={16} color={ACCENT} />
                {ex}
              </li>
            ))}
          </ul>
        )}
      </div>

      <div style={{ background: `linear-gradient(135deg, ${ACCENT}, #ffb800)`, borderRadius: 16, padding: 18, color: BG }}>
        <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 4 }}>نصيحة اليوم</div>
        <div style={{ fontSize: 13.5, opacity: 0.85 }}>
          اشرب 2-3 لتر مياه يومياً، وخد وقتك في النوم 7-8 ساعات لأفضل استشفاء عضلي.
        </div>
      </div>
    </div>
  );
}

function WorkoutTab({ user, setUser }) {
  const { profile, checkedDays = {} } = user;
  const plan = WORKOUT_TEMPLATES[profile.goal]?.[profile.level] || {};

  const toggle = async (day, idx) => {
    const key = `${day}-${idx}`;
    const updated = { ...user, checkedDays: { ...checkedDays, [key]: !checkedDays[key] } };
    setUser(updated);
    await saveUser(user.phone, updated);
  };

  return (
    <div>
      <Header title="جدول التمارين" subtitle={`خطة "${profile.goal}" - مستوى ${profile.level}`} />
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {DAYS.map((day) => {
          const exercises = plan[day] || [];
          const isRest = exercises.length === 1 && exercises[0] === "راحة";
          return (
            <div key={day} style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 14, padding: 16 }}>
              <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 10, display: "flex", justifyContent: "space-between" }}>
                <span>{day}</span>
                {isRest && <span style={{ color: "#9a9a9d", fontWeight: 600, fontSize: 13 }}>راحة 🛌</span>}
              </div>
              {!isRest && (
                <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                  {exercises.map((ex, i) => {
                    const key = `${day}-${i}`;
                    const checked = !!checkedDays[key];
                    return (
                      <div
                        key={i}
                        onClick={() => toggle(day, i)}
                        style={{
                          display: "flex", alignItems: "center", gap: 10, fontSize: 14, cursor: "pointer",
                          color: checked ? "#6b6b6e" : "#e4e4e6", textDecoration: checked ? "line-through" : "none",
                        }}
                      >
                        {checked ? <CheckCircle2 size={18} color={ACCENT} /> : <Circle size={18} color="#5a5a5d" />}
                        {ex}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

function DietTab({ user }) {
  const { profile } = user;
  const meals = DIET_TEMPLATES[profile.goal]?.[profile.level] || [];
  return (
    <div>
      <Header title="النظام الغذائي" subtitle={`نظام مقترح لهدف "${profile.goal}" - مستوى ${profile.level}`} />
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {meals.map((m, i) => (
          <div key={i} style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 14, padding: 16, display: "flex", gap: 14, alignItems: "flex-start" }}>
            <div style={{ width: 40, height: 40, borderRadius: 10, background: "#1f1f08", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
              <Utensils size={18} color={ACCENT} />
            </div>
            <div>
              <div style={{ fontWeight: 800, fontSize: 14.5, marginBottom: 4 }}>{m.meal}</div>
              <div style={{ fontSize: 13.5, color: "#bdbdc0", lineHeight: 1.6 }}>{m.items}</div>
            </div>
          </div>
        ))}
      </div>
      <div style={{ marginTop: 14, fontSize: 12.5, color: "#7d7d80", textAlign: "center", lineHeight: 1.7 }}>
        النظام ده إرشادي بشكل عام، وممكن يتعدل حسب حالتك الصحية ومتابعة المدرب.
      </div>
    </div>
  );
}

function ProgressTab({ user, setUser }) {
  const { progress, profile } = user;
  const [newWeight, setNewWeight] = useState("");
  const [err, setErr] = useState("");

  const sorted = [...progress].sort((a, b) => a.date.localeCompare(b.date));
  const minW = Math.min(...sorted.map((p) => p.weight), profile.target) - 2;
  const maxW = Math.max(...sorted.map((p) => p.weight), profile.target) + 2;

  const add = async () => {
    if (!newWeight) { setErr("اكتب وزنك"); return; }
    const today = new Date().toISOString().slice(0, 10);
    const updatedProgress = [...progress.filter((p) => p.date !== today), { date: today, weight: Number(newWeight) }];
    const updated = { ...user, progress: updatedProgress };
    setUser(updated);
    await saveUser(user.phone, updated);
    setNewWeight("");
    setErr("");
  };

  return (
    <div>
      <Header title="المتابعة" subtitle="سجل وزنك بشكل دوري لمتابعة تقدمك" />

      <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 16, padding: 18, marginBottom: 16 }}>
        <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 14 }}>سجل الوزن</div>
        {sorted.length > 0 ? (
          <div style={{ display: "flex", alignItems: "flex-end", gap: 6, height: 140, overflowX: "auto", paddingBottom: 4 }}>
            {sorted.map((p, i) => {
              const pct = maxW === minW ? 50 : ((p.weight - minW) / (maxW - minW)) * 100;
              return (
                <div key={i} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, minWidth: 36 }}>
                  <div style={{ fontSize: 11, color: "#9a9a9d", fontWeight: 700 }}>{p.weight}</div>
                  <div style={{ width: 22, height: `${Math.max(pct, 5)}%`, background: ACCENT, borderRadius: 6 }} />
                  <div style={{ fontSize: 10, color: "#6b6b6e" }}>{p.date.slice(5)}</div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{ color: "#9a9a9d", fontSize: 14 }}>لسه مفيش بيانات</div>
        )}
      </div>

      <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 16, padding: 18 }}>
        <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 12 }}>تسجيل وزن جديد (النهاردة)</div>
        <div style={{ display: "flex", gap: 10 }}>
          <input
            type="number"
            value={newWeight}
            onChange={(e) => setNewWeight(e.target.value)}
            placeholder="الوزن بالكجم"
            style={{
              flex: 1, background: "#0F0F10", border: `1.5px solid ${LINE}`, borderRadius: 10,
              padding: "12px 14px", color: "#fff", fontSize: 15, fontFamily: "inherit", outline: "none",
            }}
          />
          <button
            onClick={add}
            style={{
              background: ACCENT, color: BG, border: "none", borderRadius: 10, width: 50,
              display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer",
            }}
          >
            <Plus size={20} />
          </button>
        </div>
        {err && <div style={{ color: "#ff5c5c", fontSize: 13, marginTop: 8, fontWeight: 600 }}>{err}</div>}
      </div>
    </div>
  );
}

function ProfileTab({ user, setUser, onLogout }) {
  const [editing, setEditing] = useState(false);
  const { profile } = user;
  const [age, setAge] = useState(profile.age);
  const [height, setHeight] = useState(profile.height);
  const [target, setTarget] = useState(profile.target);
  const [goal, setGoal] = useState(profile.goal);
  const [level, setLevel] = useState(profile.level || LEVELS[1]);

  const save = async () => {
    const updated = { ...user, profile: { ...profile, age, height, target, goal, level } };
    setUser(updated);
    await saveUser(user.phone, updated);
    setEditing(false);
  };

  const currentWeight = user.progress[user.progress.length - 1]?.weight ?? profile.weight;

  return (
    <div>
      <Header title="البروفايل" />
      <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 20 }}>
        <div style={{
          width: 60, height: 60, borderRadius: "50%", background: ACCENT,
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24, fontWeight: 800, color: BG,
        }}>
          {user.name.charAt(0)}
        </div>
        <div>
          <div style={{ fontWeight: 800, fontSize: 18 }}>{user.name}</div>
          <div style={{ color: "#9a9a9d", fontSize: 13 }}>{user.phone}</div>
        </div>
      </div>

      <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 16, padding: 18, marginBottom: 14 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
          <span style={{ fontWeight: 800, fontSize: 15 }}>بياناتي</span>
          <span onClick={() => setEditing(!editing)} style={{ color: ACCENT, cursor: "pointer", display: "flex", alignItems: "center", gap: 4, fontSize: 13, fontWeight: 700 }}>
            <Edit3 size={14} /> {editing ? "إلغاء" : "تعديل"}
          </span>
        </div>

        {!editing ? (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <Row label="السن" value={`${profile.age} سنة`} />
            <Row label="الوزن الحالي" value={`${currentWeight} كجم`} />
            <Row label="الطول" value={`${profile.height} سم`} />
            <Row label="الوزن المستهدف" value={`${profile.target} كجم`} />
            <Row label="الهدف" value={profile.goal} />
            <Row label="المستوى" value={profile.level || "متوسط"} />
          </div>
        ) : (
          <div>
            <Input label="السن" type="number" value={age} onChange={(e) => setAge(e.target.value)} />
            <Input label="الطول (سم)" type="number" value={height} onChange={(e) => setHeight(e.target.value)} />
            <Input label="الوزن المستهدف (كجم)" type="number" value={target} onChange={(e) => setTarget(e.target.value)} />
            <Select label="الهدف" options={GOALS} value={goal} onChange={(e) => setGoal(e.target.value)} />
            <Select label="المستوى" options={LEVELS} value={level} onChange={(e) => setLevel(e.target.value)} />
            <Button onClick={save}>حفظ التعديلات</Button>
          </div>
        )}
      </div>

      <Button variant="ghost" onClick={onLogout}>تسجيل خروج</Button>
    </div>
  );
}

function Row({ label, value }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 14, borderBottom: `1px solid ${LINE}`, paddingBottom: 8 }}>
      <span style={{ color: "#9a9a9d" }}>{label}</span>
      <span style={{ fontWeight: 700 }}>{value}</span>
    </div>
  );
}

const TABS = [
  { id: "home", label: "الرئيسية", icon: Flame },
  { id: "workout", label: "التمارين", icon: Dumbbell },
  { id: "diet", label: "التغذية", icon: Utensils },
  { id: "progress", label: "المتابعة", icon: TrendingUp },
  { id: "profile", label: "حسابي", icon: User },
];

export default function App() {
  const [user, setUser] = useState(null);
  const [tab, setTab] = useState("home");
  const [loadingSession, setLoadingSession] = useState(true);

  useEffect(() => {
    (async () => {
      try {
        const phone = localStorage.getItem("session:lastUser");
        if (phone) {
          const u = await loadUser(JSON.parse(phone));
          if (u) setUser(u);
        }
      } catch {}
      setLoadingSession(false);
    })();
  }, []);

  const handleLogin = async (u) => {
    setUser(u);
    try { localStorage.setItem("session:lastUser", JSON.stringify(u.phone)); } catch {}
  };

  const handleLogout = async () => {
    try { localStorage.removeItem("session:lastUser"); } catch {}
    setUser(null);
    setTab("home");
  };

  const fontStyle = {
    fontFamily: "'Cairo', 'Tajawal', system-ui, sans-serif",
    direction: "rtl",
  };

  const bgStyle = {
    backgroundColor: BG,
    backgroundImage: `linear-gradient(rgba(11,11,12,0.90), rgba(11,11,12,0.90)), url(${BG_IMAGE_DATA_URI})`,
    backgroundSize: "cover",
    backgroundPosition: "center top",
    backgroundAttachment: "fixed",
    backgroundRepeat: "no-repeat",
  };

  if (loadingSession) {
    return (
      <div style={{ ...fontStyle, minHeight: "100vh", background: BG, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <Logo size={36} showCoach />
      </div>
    );
  }

  if (!user) {
    return (
      <div style={{ ...fontStyle, ...bgStyle, minHeight: "100vh", color: "#fff" }}>
        <AuthScreen onLogin={handleLogin} />
      </div>
    );
  }

  if (!user.onboarded) {
    return (
      <div style={{ ...fontStyle, ...bgStyle, minHeight: "100vh", color: "#fff" }}>
        <Onboarding user={user} onDone={setUser} />
      </div>
    );
  }

  return (
    <div style={{ ...fontStyle, ...bgStyle, minHeight: "100vh", color: "#fff", paddingBottom: 76 }}>
      <div style={{ position: "sticky", top: 0, background: "rgba(11,11,12,0.85)", backdropFilter: "blur(6px)", borderBottom: `1px solid ${LINE}`, padding: "14px 20px", zIndex: 10, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <Logo size={26} />
        <a href="https://wa.me/201019598917" target="_blank" rel="noopener noreferrer" style={{ color: "#25D366", display: "flex", alignItems: "center" }}>
          <MessageCircle size={22} />
        </a>
      </div>
      <div style={{ padding: "18px 20px", maxWidth: 480, margin: "0 auto" }}>
        {tab === "home" && <HomeTab user={user} />}
        {tab === "workout" && <WorkoutTab user={user} setUser={setUser} />}
        {tab === "diet" && <DietTab user={user} />}
        {tab === "progress" && <ProgressTab user={user} setUser={setUser} />}
        {tab === "profile" && <ProfileTab user={user} setUser={setUser} onLogout={handleLogout} />}
      </div>

      <div style={{
        position: "fixed", bottom: 0, left: 0, right: 0, background: "rgba(23,23,24,0.92)", backdropFilter: "blur(6px)", borderTop: `1px solid ${LINE}`,
        display: "flex", justifyContent: "space-around", padding: "10px 0 14px", maxWidth: 480, margin: "0 auto",
      }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <div
            key={id}
            onClick={() => setTab(id)}
            style={{
              display: "flex", flexDirection: "column", alignItems: "center", gap: 4, cursor: "pointer",
              color: tab === id ? ACCENT : "#6b6b6e", fontSize: 11, fontWeight: 700, width: 60,
            }}
          >
            <Icon size={20} />
            {label}
          </div>
        ))}
      </div>
    </div>
  );
}
